import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire input as a single string
        String input = new String(System.in.readAllBytes());
        // Convert escaped "\n" sequences to actual newlines so that tokenisation works
        input = input.replace("\\n", "\n");
        // Use a Scanner on the processed input
        Scanner sc = new Scanner(input);
        if (!sc.hasNextInt()) return;
        int T = sc.nextInt();
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            if (!sc.hasNextInt()) break;
            int N = sc.nextInt();
            int M = sc.nextInt();
            int[][] mat = new int[N][M];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    if (sc.hasNextInt()) {
                        mat[i][j] = sc.nextInt();
                    }
                }
            }
            for (int i = N - 1; i >= 0; i--) {
                for (int j = 0; j < M; j++) {
                    out.append(mat[i][j]);
                    if (j + 1 < M) out.append(' ');
                }
                out.append('\n');
            }
            if (tc + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

